import{_ as t,o as e,c as r,a2 as s}from"./chunks/framework.Cr-Z7ngm.js";const f=JSON.parse('{"title":"余额通","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/cash-plus.md","filePath":"zh-CN/funds-and-wealth/cash-plus.md"}'),l={name:"funds-and-wealth/cash-plus.md"};function n(o,a,i,d,h,u){return e(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="余额通" tabindex="-1">余额通 <a class="header-anchor" href="#余额通" aria-label="Permalink to &quot;余额通&quot;">​</a></h1><p>余额通是长桥的闲置资金增值服务，将账户内闲置资金自动投入货币市场基金，获取高于活期存款的收益，同时不影响股票交易。</p><h2 id="为什么需要余额通" tabindex="-1">为什么需要余额通 <a class="header-anchor" href="#为什么需要余额通" aria-label="Permalink to &quot;为什么需要余额通&quot;">​</a></h2><p><strong>问题</strong>：当你把钱存在长桥账户里等待交易机会时，这些现金闲置无法获利。银行活期存款利率极低。</p><p><strong>解决方案</strong>：余额通自动将闲置资金投入货币市场基金，利用你的空闲现金获取更高收益——同时保持完全的流动性：你可以随时提取这些资金用于买入股票，无需额外操作。</p><p><strong>核心优势</strong>：</p><ul><li>收益率<strong>远高于</strong>活期存款（约 3-5% 年化 vs 银行 0.3% 以下）</li><li><strong>完全自动</strong>——资金到账即自动转入，无需手动操作</li><li><strong>随时可用</strong>——卖出基金立即到账，不阻碍交易</li></ul><h2 id="本节导航" tabindex="-1">本节导航 <a class="header-anchor" href="#本节导航" aria-label="Permalink to &quot;本节导航&quot;">​</a></h2><ul><li><a href="/funds-and-wealth/余额通/香港余额通">香港余额通</a> — 港币资金的增值方式与基金选择</li><li><a href="/funds-and-wealth/余额通/新加坡余额通">新加坡余额通</a> — 新币资金的增值方式与基金选择</li><li><a href="/funds-and-wealth/余额通/余额通交易规则">余额通交易规则</a> — 买入、赎回规则与到账时间</li><li><a href="/funds-and-wealth/余额通/余额通常见问题">余额通常见问题</a> — 与其他产品的区别、费用、税务等</li></ul>',9)])])}const p=t(l,[["render",n]]);export{f as __pageData,p as default};
